scripts.push({
  name: "Query String to JSON",
  description: "Converts URL query string parameters to JSON object",
  author: "Ota Mares <ota@mares.one>",
  icon: "website",
  tags: "url,query,params,json,convert,decode",
  execute: function(require, state) {
/**
	{
		"api":1,
		"name":"Query String to JSON",
		"description":"Converts URL query string parameters to JSON object",
		"author":"Ota Mares <ota@mares.one>",
		"icon":"website",
		"tags":"url,query,params,json,convert,decode"
	}
**/

function convertToJson(urlParams) {

    return urlParams
        .replace(/\[\d?\]=/gi, '=')
        .split('&')
        .reduce((result, param) => {
            var [key, value] = param.split('=');
            value = decodeURIComponent(value || '');

            if (!result.hasOwnProperty(key)) {
                result[key] = value;

                return result;
            }

            result[key] = [...[].concat(result[key]), value]

            return result
        }, {});
}

function main(input)
{
    try {
        input.text = JSON.stringify(convertToJson(input.text));
    } catch (error) {
        input.postError("Unable to parse given string")
    }

}

    if (typeof main === "function") main(state);
  }
});

