scripts.push({
  name: "Contrasting Color",
  description: "Determines best contrasting text color (black/white) for hex colors with WCAG ratios",
  author: "Sunny Walker",
  icon: "color-wheel",
  tags: "contrast,color,wcag",
  execute: function(require, state) {
/**
{
    "api": 1,
    "name": "Contrasting Color",
    "description": "Determines best contrasting text color (black/white) for hex colors with WCAG ratios",
    "author": "Sunny Walker",
    "icon": "color-wheel",
    "tags": "contrast,color,wcag"
}
**/

function main(input) {
  let lines = input.fullText.split("\n");
  let o = lines.map(c => betterColor(c));
  input.fullText = o.join("\n");
}

// convert #rrggbb into its integer r, g, b components
const hex2Rgb = hex => {
  const rgb = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return rgb ? {
    r: parseInt(rgb[1], 16),
    g: parseInt(rgb[2], 16),
    b: parseInt(rgb[3], 16)
  } : null;
};

// calculate the luminance of a color
const luminance = hex => {
  var rgb = hex2Rgb(hex);
  var a = [rgb.r, rgb.g, rgb.b].map(v => {
    v /= 255;
    return (v <= 0.03928) ? v / 12.92 : Math.pow(((v + 0.055) / 1.055), 2.4);
  });
  return a[0] * 0.2126 + a[1] * 0.7152 + a[2] * 0.0722;
};

// calculate the contrast ratio between two colors
const contrast = (c1, c2) => {
  const l1 = luminance(c1) + .05;
  const l2 = luminance(c2) + .05;
  let ratio = l1 / l2;
  if (l2 > l1) {
    ratio = 1 / ratio;
  }
  return Math.floor(ratio * 100) / 100;
};

// convert #rbg to #rrggbb
const normalizeHex = hex => hex.replace(/^#?([a-f\d])([a-f\d])([a-f\d])$/i, '#$1$1$2$2$3$3');

// determine the WCAG 2.0 contrast ratio level
const wcagLevel = ratio => ratio >= 7 ? 'AAA' : ratio >= 4.5 ? 'AA' : 'fail';

// determine the better contrasting color for a color
const betterColor = hex => {
  const h = normalizeHex(hex);
  if (!h.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i)) {
    return hex;
  }
  var w = contrast(h, '#ffffff');
  var b = contrast(h, '#000000');
  var r = Math.max(w, b);
  return hex + ' // contrasts best with ' + (w > b ? '#fff' : '#000') + ' with a ratio of ' + r + ' to 1; WCAG 2.0: ' + wcagLevel(r);
};

    if (typeof main === "function") main(state);
  }
});

scripts.push({
  name: "Convert to pretty markdown table",
  description: "Converts CSV, TSV, or markdown tables to formatted markdown table with aligned columns",
  author: "xshoji",
  icon: "term",
  tags: "csv,tsv,md,markdown",
  execute: function(require, state) {
/**
{
  "api":1,
  "name":"Convert to pretty markdown table",
  "description":"Converts CSV, TSV, or markdown tables to formatted markdown table with aligned columns",
  "author":"xshoji",
  "icon":"term",
  "tags":"csv,tsv,md,markdown"
}
**/
function main(input) {
  input.text = convertToPrettyMarkdownTableFormat(input.text);
}

function convertToPrettyMarkdownTableFormat(input) {
  const list = input.trim().replace(/^(\r?\n)+$/g, "\n").split("\n").map(v => v.replace(/^\||\|$/g, ""));
  const delimiter = [`|`, `\t`, `","`, `,`].find(v => list[0].split(v).length > 1);
  if (delimiter === `|`) {
    // If input text is markdown table format, removes header separator.
    list.splice(1, 1);
  }
  const tableElements = list.map(record => record.split(delimiter).map(v => v.trim()));
  const calcBytes = (character) => {
    let length = 0;
    for (let i = 0; i < character.length; i++) {
      const c = character.charCodeAt(i);
      // Multibyte handling
      (c >= 0x0 && c < 0x81) || (c === 0xf8f0) || (c >= 0xff61 && c < 0xffa0) || (c >= 0xf8f1 && c < 0xf8f4) ? length += 1 : length += 2;
    }
    return length;
  };
  const columnMaxLengthList = tableElements[0].map((v, i) => i).reduce((map, columnIndex) => {
    let maxLength = 0;
    tableElements.forEach(record => maxLength < calcBytes(record[columnIndex]) ? maxLength = calcBytes(record[columnIndex]) : null);
    if (maxLength === 1) {
      // Avoids markdown header line becomes only ":" ( ":-" is correct. ).
      maxLength = 2;
    }
    map[columnIndex] = maxLength;
    return map;
  }, {})
  const formattedTableElements = tableElements.map(record => record.map((value, columnIndex) => value + "".padEnd(columnMaxLengthList[columnIndex] - calcBytes(value), " ")));
  const headerValues = formattedTableElements.shift();
  const tableLine = headerValues.map(v => "".padStart(calcBytes(v), "-").replace(/^./, ":"));
  formattedTableElements.unshift(tableLine);
  formattedTableElements.unshift(headerValues);
  return formattedTableElements.map(record => "| " + record.join(" | ") + " |").join("\n");
}

    if (typeof main === "function") main(state);
  }
});

